def find_max_and_value_pair(nums):
    if len(nums) < 2:
        return 0

    max_val = max(nums)
    if max_val == 0:
        return 0

    max_bit = max_val.bit_length() - 1

    max_and_val = 0

    for bit in range(max_bit, -1, -1):
        current_prefix = max_and_val | (1 << bit)

        count = 0
        for num in nums:
            if (num & current_prefix) == current_prefix:
                count += 1

        if count >= 2:
            max_and_val = current_prefix

    return max_and_val
